import{_ as a,o as t,c as b,j as r,a as p,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"炎之呼吸","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/武技类/白刃类/全集中呼吸法/炎之呼吸.md","filePath":"4.资源分区/6.技艺及称号/武技类/白刃类/全集中呼吸法/炎之呼吸.md"}'),s={name:"4.资源分区/6.技艺及称号/武技类/白刃类/全集中呼吸法/炎之呼吸.md"};function o(d,e,l,_,i,c){return t(),b("div",null,[...e[0]||(e[0]=[r("h1",{id:"炎之呼吸",tabindex:"-1"},[p("炎之呼吸 "),r("a",{class:"header-anchor",href:"#炎之呼吸","aria-label":'Permalink to "炎之呼吸"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新世短歌039")])])],-1),n('<h1 id="炎之呼吸-1" tabindex="-1">炎之呼吸 <a class="header-anchor" href="#炎之呼吸-1" aria-label="Permalink to &quot;炎之呼吸&quot;">​</a></h1><p>炎之呼吸<br> 前置：呼吸法<br> 下属技艺使用条件：剑/刀类近战武器</p><p>【呼吸】<br> 拥有该词条的单位在进行一次以生理属性作为关键属性的攻击前须投掷一个D10的自然骰，若出目不大于呼吸层数，则令这次攻击造成的伤害增加一半并消耗一层呼吸层数。<br> 一个单位的具有呼吸层数上限为10层。<br> 呼吸层数会在战斗结束时清空。</p><p>炎之呼吸一之型-不知火：<br> D+500<br> 以火炎爆发般的势头对目标进行高速突进接近敌人并进行斩首。<br> 以标准动作消耗1点呼吸法发动，进行一次白刃攻击，这次攻击固定攻击头部，且无视2点特殊部位减值，这次攻击附带【融毁1】，在攻击结束后，获得1层【呼吸】。<br> ——额外支付D+500，将该技艺差价升级至C级，<br> 这次攻击附带的融毁提升至【融毁5】，并且在攻击结束后获得【呼吸】的层数提升至2层。</p><p>二之型-升天炽炎<br> D+500<br> 自下而上，猛炎般的弧形斩击。<br> 以一个标准动作消耗2点呼吸法进行一次白刃攻击，本次攻击结束后获得1层【呼吸】，若当前已经具有2层及以上【呼吸】，那么这次攻击还会额外具有【破甲5】。<br> ——额外支付D+500，将该技艺差价升级至C级，<br> 消耗的呼吸法增加至4点，这次攻击获得【毁灭】，若当前【呼吸】层数大于5层，那么这次攻击的加骰额外上升一级（最高8加骰）。</p><p>炎之呼吸三之型-气炎万象<br> D+1000<br> 三之型：<br> 自上而下，对目标砍出伴随烈焰的一击<br> 以一个标准动作消耗2点呼吸法使用，若上一个使用的技艺为[二之型-升天炽炎]，那么消耗的呼吸法减少至1点，本次攻击检定具有【9加骰】，在攻击结束后获得1层【呼吸】。<br> ——额外支付D+500，将该技艺差价升级至C级，<br> 在上一级的基础上，消耗的呼吸法增加至6点，攻击的加骰等级提升至8加骰，攻击结束后再获得1层【呼吸】。</p><p>炎之呼吸四之型-盛炎漩涡：<br> D+1000<br> 以自身为中心，挥出涡漩状的斩击，此招可以化解敌方的进攻。<br> 以一个整轮动作进行一次白刃攻击，这次攻击将会同时命中触及范围内的全部敌人，随后进行一次格挡行为，在这次格挡中获得耐力上的传奇属性*1点范围伤害吸收。</p><p>炎之呼吸五之型-炎虎：<br> D+500<br> 向前突刺，并挥出烈焰之虎的巨型火焰斩击，向敌人攻过去。<br> 以一个标准动作消耗1点呼吸法能量发动，你先移动5米，然后挥出具有猛虎幻象的一次白刃攻击，本次攻击时你的武器暂时具有【融毁5】。</p><p>炎之呼吸九之型-炼狱：<br> B+2000<br> 炎之呼吸的终极奥义，全身包裹着灼热的地狱业火并像流星一般进行突进，能够瞬间对敌人造成大面积伤害。<br> 以一整轮动作消耗10点呼吸法发动，若这会导致【呼吸过载】，那么你可以改为受到不可减免不可吸收的严重伤害，直到受到的严重伤害达到你本应支付的呼吸法数量，<br> 进行一次冲锋攻击，本次冲锋攻击将会直接带着业炎斩击敌人，冲锋时有效距离取最大值计算，造成的最终伤害增加一倍，若此时你的【呼吸】层数在7及以上，那么在其触发【呼吸】的暴击效果时，伤害额外增加一半，冲锋过程中羽织将在呼吸法的作用下自然鼓动，如同燃起烈火，这次攻击将会附带【碾压】。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',11)])])}const D=a(s,[["render",o]]);export{f as __pageData,D as default};
